export const meta = { name: 'parallel_primality', description: 'Independently check whether 17 is prime and synthesize the surviving evidence.', phases: [{ title: 'Independent checks' }, { title: 'Synthesis' }] };

phase('Independent checks');
const checks = await parallel([
  () => agent('Independently determine whether 17 is prime using trial division. Return concise evidence: method, divisors checked, and conclusion.', {
    label: 'trial division',
    tier: 'small',
    schema: {
      type: 'object',
      properties: {
        method: { type: 'string' },
        conclusion: { type: 'boolean' },
        evidence: { type: 'string' }
      },
      required: ['method', 'conclusion', 'evidence'],
      additionalProperties: false
    }
  }),
  () => agent('Independently determine whether 17 is prime using a mathematical primality criterion distinct from a plain exhaustive explanation. Return concise evidence: method, facts checked, and conclusion.', {
    label: 'sqrt criterion',
    tier: 'small',
    schema: {
      type: 'object',
      properties: {
        method: { type: 'string' },
        conclusion: { type: 'boolean' },
        evidence: { type: 'string' }
      },
      required: ['method', 'conclusion', 'evidence'],
      additionalProperties: false
    }
  })
]);

const surviving = checks.filter(Boolean);
const failedChecks = checks.map((check, index) => check ? null : ['trial division', 'sqrt criterion'][index]).filter(Boolean);

phase('Synthesis');
const result = await agent(`Synthesize only the surviving independent evidence below about whether 17 is prime. A missing checker is tolerated. Return a compact JSON object with prime, evidence, and failedChecks.\n\nSurviving evidence: ${JSON.stringify(surviving)}\nFailed checks: ${JSON.stringify(failedChecks)}`, {
  label: 'evidence synthesis',
  tier: 'big',
  schema: {
    type: 'object',
    properties: {
      prime: { type: 'boolean' },
      evidence: { type: 'array', items: { type: 'string' } },
      failedChecks: { type: 'array', items: { type: 'string' } }
    },
    required: ['prime', 'evidence', 'failedChecks'],
    additionalProperties: false
  }
});

return result || { prime: surviving.every(check => check.conclusion), evidence: surviving.map(check => check.evidence), failedChecks };

